import type { HTMLAttributes } from "react";

import { cn } from "../../lib/cn";

type ProgressTone = "accent" | "success" | "danger" | "neutral";

export type ProgressBarProps = HTMLAttributes<HTMLDivElement> & {
  value: number;
  max?: number;
  tone?: ProgressTone;
};

const railClasses: Record<ProgressTone, string> = {
  accent: "bg-[color:color-mix(in_srgb,var(--primary)_12%,transparent)]",
  success: "bg-emerald-100",
  danger: "bg-red-100",
  neutral: "bg-[var(--muted)]",
};

const fillClasses: Record<ProgressTone, string> = {
  accent: "bg-[var(--primary)]",
  success: "bg-emerald-600",
  danger: "bg-red-600",
  neutral: "bg-[var(--foreground)]",
};

export function ProgressBar({ className, value, max = 100, tone = "accent", ...props }: ProgressBarProps) {
  const safeMax = Number.isFinite(max) && max > 0 ? max : 100;
  const percent = Math.max(0, Math.min(100, (value / safeMax) * 100));

  return (
    <div
      className={cn("h-2 overflow-hidden rounded-full", railClasses[tone], className)}
      role="progressbar"
      aria-valuemin={0}
      aria-valuemax={safeMax}
      aria-valuenow={Math.round(Math.max(0, Math.min(safeMax, value)))}
      {...props}
    >
      <div
        className={cn("h-full rounded-full transition-all duration-300", fillClasses[tone])}
        style={{ width: `${percent}%` }}
      />
    </div>
  );
}
